import{_ as p,o as a,c as i,ag as n}from"./chunks/framework.DXGyWiRo.js";const t="/images/uebung011.jpg",r="/images/uebung012.jpg",y=JSON.parse('{"title":"Übung Lektion 10","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung10.md","filePath":"lektionen/uebung10.md"}'),s={name:"lektionen/uebung10.md"};function l(h,e,o,u,d,m){return a(),i("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-10" tabindex="-1">Übung Lektion 10 <a class="header-anchor" href="#ubung-lektion-10" aria-label="Permalink to &quot;Übung Lektion 10&quot;">​</a></h1><p>A) Bilden Sie das Passiv zu folgenden Verbformen (mit Übersetzung der Verbform), d.h. das Passiv, das der Verbform in Person und Zahl entspricht:</p><ol><li>sṛjati सृजति : sṛjyate सृज्यते</li><li>yudhyate युध्यते : yudhyate युध्यते</li><li>bhavanti भवन्ति : bhūyante भूयन्ते</li><li>yajati यजति : ijyate इज्यते</li><li>nṛtyati नृत्यति : nṛtyate नृत्यते</li><li>nayanti नयन्ति : nīyante नीयन्ते</li><li>smarati स्मरति : smaryate स्मर्यते</li><li>śṛṇvanti शृण्वन्ति : śrūyante श्रूयन्ते</li><li>pāśyati पश्यति (Passiv wird von dṛś gebildet!) : dṛśyate दृश्यते</li><li>jayanti जयन्ति : jīyante जीयन्ते</li><li>kurvate कुर्वते : kriyante क्रियन्ते</li><li>āpnuvanti आप्नुवन्ति : āpyante आप्यन्ते</li><li>viśati विशति : viśyate विश्यते</li><li>khādanti खादन्ति : khādyante खाद्यन्ते</li><li>sunoti सुनोति : sūyate सूयन्ते</li><li>gacchati गच्छति : gamyate गम्यते</li><li>manyante मन्यन्ते : manyante मन्यन्ते</li><li>labhante लभन्ते : labhyante लभ्यन्ते</li><li>rakṣanti रक्षन्ति : rakṣyante रक्ष्यन्ते</li><li>vadanti वदन्ति : udyante उद्यन्ते</li><li>pṛcchanti पृच्छन्ति : pṛcchyante पृच्छ्यन्ते</li><li>tanvanti तन्वन्ति (2 Formen!) : tanyante / tāyante तन्यन्ते तायन्ते</li></ol><p>B) Bilden Sie den Instrumentalis singular und plural zu allen bisher gelernten Nomina</p><p>C) Setzen Sie folgende Sätze ins Passiv und übersetzen Sie sie:</p><p>1. brāhmaṇo devīm yajati. ब्राह्मणो देवीं यजति |</p><p>brāhmaṇena devījyate.</p><p>ब्राह्मणेन देवीज्यते ।</p><p>2. sādhuḥ svargaṃ gacchati. साधुः स्वर्गं गच्छति |</p><p>sādhunā svargaṃ / svargo gamyate.</p><p>साधुना स्वर्गं गम्यते । साधुना स्वर्गो गम्यते ।</p><p>3. śūdraṃ jayati. शूद्रं जयति |</p><p>śūdro jīyate.</p><p>शूद्रो जीयते ।</p><p>4. guruḥ phalāni khādati. गुरुः फलानि खादति |</p><p>guruṇā phalāni khādyante.</p><p>गुरुना फलानि खाद्यन्ते ।</p><p>5. gurūñchṛṇoti. गुरूञ्छृणोति |</p><p>guravaḥ śrūyante.</p><p>गुरवः श्रूयन्ते ।</p><p>6. ko &#39;gniṃ paśyati. को ऽग्निं पश्यति |</p><p>kenāgnir dṛśyate.</p><p>केनाग्निर्दृश्यते ।</p><p>7. ayaṃ kavirmantraṃ smarati. अयं कविर्मन्त्रं स्मरति |</p><p>anena kavinā mantraḥ smaryate.</p><p>अनेन कविना मन्त्रः स्मर्यते ।</p><p>8. iyaṃ devī kṣatriyā rakṣati. इयं देवी क्त्रिया रक्षति |</p><p>anayā devyā kṣatriyā rakṣyante.</p><p>अनया देव्या क्षत्रिया रक्ष्यन्ते ।</p><p>9. kṣatriyā viṣṇuṃ yajante. क्षत्रिया विष्णुं यजन्ते | (2 Möglichkeiten)</p><p>kṣatriyair viṣṇur ijyate / kṣatriyābhir viṣṇur ijyate.</p><p>क्षत्रियैर्विष्णुरिज्यते । क्षत्रियाभिर्विष्णुरिज्यते ।</p><p>10. brāhmaṇo &#39;gniṃ karoti. ब्राह्मणो ऽग्निं करोति |</p><p>brāhmaṇenāgniḥ kriyate.</p><p>ब्राह्मणेनाग्निः क्रियते ।</p><p>11. vaiśyā imaṃ grāmaṃ gacchanti. वैश्या इमं ग्रामं गच्छन्ति | (2 Möglichkeiten)</p><p>vaiśyair / vaiśyābhir imaṃ grāmaṃ / ayaṃ grāmo gamyate.</p><p>वैश्यैरिमं ग्रामं गम्यते । वैश्यैरयं ग्रामो गम्यते । वैश्याभिरिमं ग्रामं गम्यते । वैश्याभिरयं ग्रामो गम्यते ।</p><p>Vaiśyas / Vaiśyafrauen gehen in dieses Dorf.</p><p>12. ete gurūṃstu śṛṇvanti. एते गुरूंस्तु शृण्वन्ति |</p><p>etair guravas tu śrūyante.</p><p>एतैर्गुरवस्तु श्रूयन्ते ।</p><p>Sie hören aber auf ihre Meister.</p><p>13. sādhuḥ svargamāpnoti. साधुः स्वर्गमाप्नोति |</p><p>sādhunā svarga āpyate.</p><p>साधुना स्वर्ग आप्यते ।</p><p>Ein Heiliger aerlangt den Himmel.</p><p>14. brāhmāṇāḥ somaṃ sunvanti. ब्राह्मणाः सोमं सुन्वन्ति |</p><p>brāhmaṇaiḥ somaḥ sūyate.</p><p>ब्राह्मणैः सोमः सूयते ।</p><p>Brahmanen pressen Soma.</p><p>15. paśūṃllabhate. पशूल्ंलभते |</p><p>paśavo labhyante.</p><p>पशवो लभ्यन्ते ।</p><p>Man bekommt Haustiere.</p><p>16. ke yodhāḥ kṣatriyaiḥ saha yudhyante. के योधाः क्षत्रियैः सह युध्यन्ते |</p><p>kair yodhaiḥ kṣatriyaiḥ saha yudhyate.</p><p>कैर्योधैः क्षत्रियैः सह युध्यते ॥</p><p>Welche Soldaten kämpfen (zusammen) mit den Kṣatriyas?</p><p>D) Übersetzen Sie ins Sanskrit:</p><p>1. Ein Brahmane geht mit einem Vaiśya ins Dorf.</p><p>brāhmano vaiśyena saha grāmaṃ gacchati.</p><p>ब्राह्मणो वैश्येन सह ग्रामं गच्छति ।</p><p>2. Er verehrt Viṣṇu mit einem Opfer. (Opfer yajña ausdrücken!)</p><p>yajñena viṣṇuṃ yajati / yajate.</p><p>यज्ञेन विष्णुं यजति / यजते ।</p><p>3. Der Veda wird śruti genannt. (vad)</p><p>vedaḥ śrutir (ity) udyate.</p><p>वेदः श्रुतिरित्युद्यते ।</p><p>4. Man spannt die Webkette auf. (2 Möglichkeiten)</p><p>tantraṃ tanyate / tāyate / tanvanti.</p><p>तन्त्रं तन्यते / तायते / तन्वन्ति ।</p><p>5. Lehrer fragen. (Passivkonstruktion)</p><p>gurubhiḥ pṛcchyate.</p><p>गुरुभिः प्र्च्छ्यते ।</p><p>6. Das Auge führt. (Passivkonstruktion) (Auge und Ohr werden sonst normalerweise im Dual verwendet)</p><p>netreṇa nīyate.</p><p>नेत्रेण नीयते ।</p><p>7. Der Dichter sieht eine Gottheit. (Passivkonstruktion)</p><p>kavinā devatā dṛśyate.</p><p>कविना देवता दृश्यते ।</p><p>8. Wer (fem.) hütet das Mädchen? (Passivkonstruktion)</p><p>kayā bālā rakṣyate.</p><p>कया बाला रक्ष्यते ।</p><p>9. Der Kṣatriya verehr den HERRN mit einem Opfer. (Passivkonstruktion, ohne das Wort yajña zu verwenden)</p><p>kṣatriyeṇeśvara ijyate.</p><p>क्षत्रियेनेश्वर इज्यते ।</p><p>10. Durch Freigebigkeit erreicht ein Anhänger des Buddha einen Himmel.</p><p>dānena śrāvakaḥ svargam āpnoti / aśnute.</p><p>दानेन श्रावकः स्वर्गमाप्नोति / स्वर्गमश्नुते ।</p><p><img src="'+t+'" alt=""><br> Abb.: grāmaḥ =  ग्रामः, Madhya Pradesh<br> [Bildquelle: Carol Mitchell. -- <a href="http://www.flickr.com/photos/webethere/2168794710/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/webethere/2168794710/</a>. -- Zugriff am 2008-11-29. -- <a href="http://creativecommons.org/licenses/by-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine Bearbeitung)]</p><p>Lesen und übersetzen Sie und setzen Sie ins Passiv:</p><p>क</p><p>१.</p><blockquote><p>मक्सिका व्रणमिच्छन्ति<br> धनमिच्छन्ति पार्थिवाः |<br> नीचाः कलहमिच्छन्ति<br> शान्तिमिच्छन्ति साधवः ||</p><p>मक्षिकाभिर्व्रण इष्यते<br> धनमिष्यते पार्थिवैः ।<br> नीचैः कलह इष्यते<br> शान्तिरिष्यते साधुभिः ॥</p><p>Fliegen wünschen sich eine Wunde,<br> Könige wünschen sich Reichtum,<br> Niederträchtige wünschen Streit,<br> Frieden wünschen Heilige.</p></blockquote><p>२. नरान्सृजति देवः |</p><p>नरा देवैः सृज्यन्ते ।</p><p>Die Götter erschaffen die Menschen.</p><p>३. कवयो धनं लुभ्यन्ति |</p><p>कविभिर्धनं लभ्यते ।</p><p>Dichter begehren Reichtum.</p><p>४. ऋषिः सूक्तानि पश्यति |</p><p>ऋषिणा सूक्तानि दृश्यन्ते ।</p><p>Der vedische Weise sieht die vedischen Lieder.</p><p>५. विष्णुमृषिर्यजति |</p><p>विष्णुरृषिणेज्यते ।</p><p>Der vedische Weise opfert Viṣṇu.</p><p>६. गुरूञ्शिष्यांश्च पश्यति |</p><p>गुरवः शिष्याश्च दृश्यन्ते ।</p><p>Er sieht Meister und Schüler.</p><p>७. स्वर्गं लभन्ते |</p><p>स्वर्गो लभ्यते ।</p><p>Sie erlangen den Himmel.</p><p>८. अत्रर्षिर्भानुं वन्दते |</p><p>अत्रर्षिणा भानुर्वन्स्यते ।</p><p>Dort begrüßt ein vedischer Weiser die Sonne.</p><p>९. ग्रामं गच्छन्ति |</p><p>ग्रामं गम्यते । ग्रामो गम्यते ।</p><p>Sie gehen ins Dorf.</p><p>१०. दानानि वर्षन्ति नृपाः ||</p><p>दानानि वृष्यन्ते नृपैः ॥</p><p>Könige lassen Geschenke regnen.</p><p>ख</p><p>१. सदा देवान्स्मरन्ति |</p><p>सदा देवाः स्मर्यन्ते।</p><p>Sie vergegenwärtigen sich stets die Götter.</p><p>२. ऋषिभी रामो वसति |</p><p>ऋषिभिः सह रामेणोष्यते ।</p><p>Rāma wohnt bei den vedischen Weisen.</p><p>३. हरिं क्षीरेण यजति |</p><p>हरिः क्षीरेणेज्यते ।</p><p>Er verehrt Hari mit einem Milchopfer.</p><p>४. मार्गेण ग्रामं गच्छन्ति |</p><p>मार्गेन ग्रामं गम्यते । मार्गेन ग्रामो गम्यते ।</p><p>Sie gehen auf dem Weg ins Dorf.</p><p>५. धनेन सुखमिच्छन्ति नराः |</p><p>धनेने नरैः सुखमिष्यते ।</p><p>Die Menschen wollen Glück durch Reichtum.</p><p>६. एवं वदन्ति |</p><p>एवमुद्यते ।</p><p>So sagt man.</p><p>७. शान्त्यर्षय इह शोभन्ते |</p><p>शान्त्यर्षिभिरिह शुभ्यते ।</p><p>Auf Erden glänzen Heilige durch Friedsamkeit.</p><p>८. कपयः फलानि खादन्ति |</p><p>कपिभिः फलानि खाद्यन्ते ।</p><p>Affen fressen Früchte.</p><p>९. गजो गच्छति |</p><p>गजेन गम्यते ।</p><p>Der Elefant läuft.</p><p>१०. हरिर्गृहं गच्छति |</p><p>हरिणा गृहं गम्यते ।</p><p>Hari geht nachhause.</p><p>११. सारथी रथं नयति ||</p><p>सारथिना रथो नीयते ॥</p><p>Der Fuhrmann lenkt den Wagen.</p><p><img src="'+r+'" alt=""><br> Abb.: सारथी रथं नयति |<br> [Bildquelle: World Bank Photo Collection. -- <a href="http://www.flickr.com/photos/worldbank/2277349299/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldbank/2277349299/</a>. -- Zugriff am 2008-11-29. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>Zu Lösung der <a href="./uebung11">Übungen Lektion 11 - 15</a></p>',159)])])}const c=p(s,[["render",l]]);export{y as __pageData,c as default};
